// Placeholder: Collect engagement metrics from each platform
// This will be implemented when platform APIs are fully connected
const fs = require('fs');
const path = require('path');
const queueDir = 'D:\\Joymaze-Content\\output\\queue';
const files = fs.readdirSync(queueDir).filter(f => f.endsWith('.json'));
let posted = 0, pending = 0, failed = 0;
for (const f of files) {
  const data = JSON.parse(fs.readFileSync(path.join(queueDir, f), 'utf-8'));
  for (const [, p] of Object.entries(data.platforms || {})) {
    if (p.status === 'posted') posted++;
    else if (p.status === 'failed') failed++;
    else pending++;
  }
}
return [{ json: { date: new Date().toISOString().slice(0, 10), totalPosted: posted, totalPending: pending, totalFailed: failed } }];

// Write daily stats to analytics log
const fs = require('fs');
const stats = $input.first().json;
const logPath = 'D:\\Joymaze-Content\\output\\analytics.jsonl';
fs.appendFileSync(logPath, JSON.stringify(stats) + '\n');
return [{ json: { ...stats, logged: true } }];
